  showForge(){
    UI.modal('⚒️ 대장간','장비 제작과 분해 기능이 곧 열립니다.\n\n(장비 시스템 준비 중)',null);
  },

  showChurch(){
    // 2026-05-02: 성당 modal 일괄 회복 (사용자 결정).
    //   대상: HP 가 부족한 모든 카드 (영웅 포함 — 사용자 보고: 영웅 HP 0 일 때 치료 못 하던 버그 해소).
    //   장례 옵션은 일단 보류 (별도 phase).
    const targets=this.deck.filter(c=>{
      if(c.injured)return true;
      const hp=c.currentHp!=null?c.currentHp:c.hp;
      if(hp<=0){c.injured=true;return true;}
      if(hp<c.hp)return true;
      return false;
    });
    if(targets.length===0){
      UI.modal('⛪ 성당','동료 전원의 HP 가 만전입니다.\n\n다음 전투를 준비하세요.',null);
      return;
    }
    // 비용 합산: 부상 카드는 level×2, 부분 손상은 깎인 HP 만큼 (1 HP = 0.5 골드, 최소 1).
    let totalCost=0;
    const lines=targets.map(c=>{
      const hp=c.currentHp!=null?c.currentHp:c.hp;
      let cost;
      if(c.injured){
        cost=Math.max(1,Math.floor((c.level||1)*2));
      }else{
        const diff=c.hp-hp;
        cost=Math.max(1,Math.floor(diff*0.5));
      }
      totalCost+=cost;
      const status=c.injured?'🩹 부상':`HP ${hp}/${c.hp}`;
      return `• ${c.icon||'🗡️'} ${c.name} — ${status} (${cost}💰)`;
    }).join('\n');
    if(this.gold<totalCost){
      UI.modal('⛪ 성당',`💰 부족합니다.\n\n총 ${totalCost}💰 필요 (보유 ${this.gold}💰)\n\n${lines}`,null);
      return;
    }
    UI.modal('⛪ 성당 치료',`${targets.length}명의 동료를 치료합니다.\n\n${lines}\n\n총 비용: ${totalCost}💰\n\n전원 치료하시겠습니까?\n(에너지 회복은 여관에서)`,()=>{
      this.gold-=totalCost;
      targets.forEach(c=>{c.injured=false;c.currentHp=c.hp;});
      SFX.play('heal');
      this.persist();
      UI.modal('⛪ 치료 완료','동료 전원의 HP 가 만전으로 회복되었습니다.',null);
    });
  },

  // 2026-05-02: 폐기된 grid 코드. 향후 장례(funeral) 기능 추가 시 별도 함수로 부활 예정.
  _showChurchGridLegacy(){
    UI.show('church-screen');
    document.getElementById('church-gold').textContent=this.gold;
    const injured=this.deck.filter(c=>c.injured&&!c.isHero);
    const npc=this.getNpc('church');
    const msg=injured.length?npc.greet:`부상자가 없군요. 평화로운 날입니다.`;
    const existing=document.getElementById('church-npc');if(existing)existing.remove();
    document.getElementById('church-info').insertAdjacentHTML('afterend',`<div id="church-npc">${this.renderNpcBar('church',msg)}</div>`);
    const g=document.getElementById('church-grid');g.innerHTML='';
    // 2026-04-24: 건물 Lv 시스템 폐기 — discount/honorBonus 단계별 보너스 제거.
    const discount=0;
    const honorBonus=1;
    if(!injured.length){
      g.innerHTML='<div style="color:#888;text-align:center;padding:40px;font-size:.9rem;">부상당한 동료가 없습니다.<br><span style="font-size:.75rem;color:#555;">전투에서 쓰러진 동료가 이곳에 옵니다.</span></div>';
      return;
    }
    injured.forEach(c=>{
      const cost=Math.max(1,Math.floor((c.level||1)*2*(1-discount)));
      const honorGain=Math.floor(((c.level||1)*3+(c.honor||0)*0.1)*honorBonus);
      const el=mkCardElV4(c);
      el.style.filter='grayscale(.5) brightness(.7)';
      const wrap=document.createElement('div');wrap.style.textAlign='center';
      wrap.appendChild(el);
      // Injury badge
      const badge=document.createElement('div');badge.style.cssText='color:#ff4444;font-size:.75rem;margin-top:4px;';
      badge.textContent='🩹 부상 — 출전 불가';wrap.appendChild(badge);
      // Buttons
      const btns=document.createElement('div');btns.style.cssText='display:flex;gap:6px;justify-content:center;margin-top:6px;';
      // Revive button
      const revBtn=document.createElement('button');revBtn.className='btn btn-s btn-green';
      revBtn.textContent=`✨ 치료 (${cost}💰)`;revBtn.disabled=this.gold<cost;
      revBtn.onclick=()=>{
        UI.modal('✨ 치료 확인',`${c.icon} ${c.name}을(를) ${cost}💰로 치료하시겠습니까?\n\n부상이 치유되고 HP가 만전으로 회복됩니다.\n(에너지는 여관에서 회복)`,()=>{
          // 2026-05-02: 성당 = HP 전담 / 여관 = NRG 전담 (사용자 결정). NRG reset 제거.
          this.gold-=cost;c.injured=false;c.currentHp=c.hp;
          SFX.play('heal');
          const flash=document.createElement('div');flash.className='upgrade-flash';document.body.appendChild(flash);setTimeout(()=>flash.remove(),600);
          this.persist();this.showChurch();
        });
      };
      btns.appendChild(revBtn);
      // Funeral button
      const funBtn=document.createElement('button');funBtn.className='btn btn-s btn-purple';
      funBtn.textContent=`⚰️ 장례 (+${honorGain}명예)`;
      funBtn.onclick=()=>{
        UI.modal('⚰️ 영면의 의식',`${c.icon} ${c.name}을(를) 영면에 들게 하시겠습니까?\n\n동료는 영원히 떠나지만,\n영웅의 명예가 ${honorGain} 상승합니다.`,()=>{
          // Remove from deck
          this.deck=this.deck.filter(x=>x.uid!==c.uid);
          // Give honor to hero
          const hero=this.deck.find(x=>x.isHero);
          if(hero)hero.honor=(hero.honor||0)+honorGain;
          SFX.play('death');
          this.persist();this.showChurch();
        });
      };
      btns.appendChild(funBtn);
      wrap.appendChild(btns);g.appendChild(wrap);
    });
  },

  // 2026-05-02: 구버전 modal showTraining() 정의 제거 — 신규 훈련장 화면 진입 (line 46) 으로 대체.

